    BIND(IRI(CONCAT("inferred:dimensionVector_",STR(?index_dv))) as ?graph)
    FILTER NOT EXISTS {
        GRAPH ?graph {
            ?s ?p ?o
        }
    }
}

when.sparqlAsk:

