DELETE {
    GRAPH <dist:vocab:VOCAB_QUDT-UNITS-ALL.ttl> {
        ?unit rdfs:label ?incorrectLabel .
    }
}
INSERT {
    GRAPH <dist:vocab:VOCAB_QUDT-UNITS-ALL.ttl> {
        ?unit rdfs:label ?missingLabel .
    }
    GRAPH <fix:labels:default:toDelete> {
        ?unit rdfs:label ?incorrectLabel .
    }
    GRAPH <fix:labels:default:toAdd> {
        ?unit rdfs:label ?missingLabel .
    }
}
WHERE {
    {
        GRAPH <dist:vocab:VOCAB_QUDT-UNITS-ALL.ttl> {
                ?unit rdfs:label ?incorrectLabel .
        }
        FILTER EXISTS {
            GRAPH <inferred:labels:default> {
                ?unit rdfs:label ?missingLabel .
                FILTER (
                    LANGMATCHES(
                        LANG(?missingLabel),
                        LANG(?incorrectLabel)
                    )
                )
            }
        }
        FILTER NOT EXISTS {
            GRAPH <inferred:labels:default> {
                ?unit rdfs:label ?incorrectLabel .
            }
        }
    } UNION {
        GRAPH <inferred:labels:default> {
                ?unit rdfs:label ?missingLabel .
        }
        FILTER NOT EXISTS {
            GRAPH <dist:vocab:VOCAB_QUDT-UNITS-ALL.ttl> {
