                                            INSERT {
                                                GRAPH <dist:vocab:VOCAB_QUDT-DIMENSION-VECTORS.ttl> {
                                                    ?newDimVec a qudt:QuantityKindDimensionVector ;
                                                    qudt:dimensionExponentForAmountOfSubstance        ?A ;
                                                    qudt:dimensionExponentForElectricCurrent          ?E ;
                                                    qudt:dimensionExponentForLength                   ?L ;
                                                    qudt:dimensionExponentForLuminousIntensity        ?I ;
                                                    qudt:dimensionExponentForMass                     ?M ;
                                                    qudt:dimensionExponentForThermodynamicTemperature ?H ;
                                                    qudt:dimensionExponentForTime                     ?T ;
                                                    qudt:dimensionlessExponent                        ?D ;
                                                    qudt:latexDefinition ?latex ;
                                                    rdfs:isDefinedBy <http://qudt.org/$$QUDT_VERSION$$/vocab/dimensionvector> ;
                                                    rdfs:label ?label .
                                                }
                                            }
                                            WHERE {
                                                GRAPH <dist:vocab:VOCAB_QUDT-UNITS-ALL.ttl> {
                                                ?u a qudt:Unit .
                                                ?u qudt:hasDimensionVector ?newDimVec .
                                                }
                                                FILTER NOT EXISTS {
                                                GRAPH <dist:vocab:VOCAB_QUDT-DIMENSION-VECTORS.ttl> {
                                                ?newDimVec a qudt:QuantityKindDimensionVector .}}
                                                BIND(REPLACE(STR(?newDimVec), "^.*[#/]", "") AS ?local)

# Extract each exponent (default 0 if missing)
                                                  BIND(xsd:integer(REPLACE(?local, "^.*A(-?[0-9]+).*", "$1")) AS ?A)
                                                  BIND(xsd:integer(REPLACE(?local, "^.*E(-?[0-9]+).*", "$1")) AS ?E)
                                                  BIND(xsd:integer(REPLACE(?local, "^.*L(-?[0-9]+).*", "$1")) AS ?L)
                                                  BIND(xsd:integer(REPLACE(?local, "^.*I(-?[0-9]+).*", "$1")) AS ?I)
                                                  BIND(xsd:integer(REPLACE(?local, "^.*M(-?[0-9]+).*", "$1")) AS ?M)
                                                  BIND(xsd:integer(REPLACE(?local, "^.*H(-?[0-9]+).*", "$1")) AS ?H)
                                                  BIND(xsd:integer(REPLACE(?local, "^.*T(-?[0-9]+).*", "$1")) AS ?T)
                                                  BIND(xsd:integer(REPLACE(?local, "^.*D(-?[0-9]+).*", "$1")) AS ?D)

                                                  BIND(?local AS ?label)

# Build LaTeX definition dynamically for any permutation of exponents
                                                  BIND(
                                                    STRDT(
                                                      CONCAT(
                                                        IF(?A != 0, CONCAT(" $A^{", STR(?A), "}$"), ""),
                                                        IF(?E != 0, CONCAT(" $E^{", STR(?E), "}$"), ""),
                                                        IF(?L != 0, CONCAT(" $L^{", STR(?L), "}$"), ""),
                                                        IF(?I != 0, CONCAT(" $I^{", STR(?I), "}$"), ""),
                                                        IF(?M != 0, CONCAT(" $M^{", STR(?M), "}$"), ""),
                                                        IF(?H != 0, CONCAT(" $H^{", STR(?H), "}$"), ""),
                                                        IF(?T != 0, CONCAT(" $T^{", STR(?T), "}$"), ""),
                                                        IF(?D != 0, CONCAT(" $D^{", STR(?D), "}$"), "")
                                                      ),
                                                      qudt:LatexString
                                                    ) AS ?latex
                                                  )
                                                }


                                                INSERT {
                                                GRAPH <dist:vocab:VOCAB_QUDT-UNITS-ALL.ttl> {
    ?unit a qudt:ContextualUnit, qudt:Unit ;
        qudt:hasDimensionVector ?dimensionVector ;
        rdfs:comment  ?comment ;
        rdfs:isDefinedBy <http://qudt.org/$$QUDT_VERSION$$/vocab/unit> .
}}
WHERE
{
GRAPH <dist:vocab:VOCAB_QUDT-UNITS-ALL.ttl> {
    {
        ?x qudt:hasFactorUnit/qudt:hasUnit ?unit .
        BIND("factor unit" as ?reason)
    } UNION {
        ?unit qudt:hasFactorUnit/qudt:hasUnit ?x .
        BIND("derived unit" as ?reason)
    } UNION {
        ?x qudt:scalingOf ?unit .
        BIND("base unit" as ?reason)
    } UNION {
        ?unit qudt:scalingOf ?x .
        BIND("scaled unit" as ?reason)
    }
    FILTER NOT EXISTS {
        ?unit a qudt:Unit
    }
    FILTER NOT EXISTS {
        ?unit a qudt:CurrencyUnit
    }
    FILTER NOT EXISTS {
        ?unit qudt:deprecated true
    }
    FILTER NOT EXISTS {
        ?x qudt:deprecated true
    }
    OPTIONAL {
        ?unit qudt:scalingOf/qudt:hasDimensionVector ?dimensionVector .
    }
    OPTIONAL {
        ?unit skos:broader/qudt:hasDimensionVector ?dimensionVector .
    }
    OPTIONAL {
        ?unit qudt:hasQuantityKind/qudt:hasDimensionVector ?dimensionVector .
    }
    BIND(STRLANG(CONCAT("This unit was added while generating qudt:hasFactorUnit. This unit is a ", ?reason, " of ", (REPLACE(STR(?x), "http://qudt.org/vocab/unit/", "unit:")), ", missing from the original QUDT data."), "en") as ?comment)
}}

DELETE {
    GRAPH ?graph {
        ?s ?p $this .
    }
}
INSERT {
    GRAPH ?graph {
        ?s ?p ?replacement .
    }
}
WHERE {
    GRAPH ?defGraph {
        $this qudt:deprecated true .
        $this dcterms:isReplacedBy ?replacement .
    }
    GRAPH ?graph {
        ?s ?p $this .
    }
}


