sparqlUpdate.sparql:

prefix rdfio: <https://github.com/qudtlib/rdfio/>
DELETE {
    GRAPH <rdfio:pipeline:metadata> {
        ?file rdfio:loadsInto ?graph .
    }
} INSERT {
    GRAPH <rdfio:pipeline:metadata> {
        ?newFile rdfio:loadsInto ?graph .
    }
} WHERE {
    GRAPH <rdfio:pipeline:metadata> {
        ?file rdfio:loadsInto ?graph .
    }
    BIND (IRI(REPLACE(STR(?file), "target/deprecated-in-${deprecatedInVersion}/release", "target/deprecated-in-${deprecatedInVersion}/deprecated-only")) AS ?newFile)
}


DELETE {
    GRAPH ?graph {
       ?s1 ?p1 ?o1 .
       ?o1 ?p2 ?o2 .
       ?o2 ?p1 ?o3 .
   }
} WHERE {
    GRAPH ?graph  {
        ?s1 ?p1 ?o1 .
        FILTER NOT EXISTS {
            ?s1 qudt:deprecated true .
        }
        OPTIONAL {
           ?o1 ?p2 ?o2
           OPTIONAL {
                ?o2 ?p2 ?o3 .
           }
        }
    }
    FILTER (?graph != <rdfio:pipeline:metadata>)
}

assert.sparqlSelect:
PREFIX sh: <http://www.w3.org/ns/shacl#>

SELECT ?ps ?xsdDatatype
WHERE {
    GRAPH <work:schema:typing-evidence> {
        ?ps a sh:PropertyShape ;
            sh:class ?xsdDatatype .
        FILTER(
            isIRI(?xsdDatatype)
            && STRSTARTS(STR(?xsdDatatype), "http://www.w3.org/2001/XMLSchema#")
        )
    }
}

when.sparqlAsk:
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX sh: <http://www.w3.org/ns/shacl#>
ASK {
    GRAPH <work:schema:overlay> {
        ?property a ?overlayType .
        FILTER(?overlayType IN (owl:AnnotationProperty, owl:ObjectProperty, owl:DatatypeProperty))
    }
    GRAPH <work:schema:derived> {
        ?ps a sh:PropertyShape ;
            sh:path ?property .
        FILTER(isIRI(?property))
    }
    {
        FILTER(?overlayType = owl:AnnotationProperty)
        GRAPH <work:schema:derived> {
            ?ps sh:datatype ?dt .
        }
    } UNION {
        FILTER(?overlayType = owl:ObjectProperty)
        GRAPH <work:schema:derived> {
            ?ps sh:datatype ?dt .
        }
    } UNION {
        FILTER(?overlayType = owl:DatatypeProperty)
        GRAPH <work:schema:derived> {
            ?ps sh:class ?cls .
        }
    } UNION {
        FILTER(?overlayType = owl:DatatypeProperty)
        GRAPH <work:schema:derived> {
            ?ps sh:node ?node .
        }
    } UNION {
        FILTER(?overlayType = owl:DatatypeProperty)
        GRAPH <work:schema:derived> {
            ?ps sh:nodeKind ?nk .
            FILTER(?nk IN (sh:IRI, sh:BlankNodeOrIRI))
        }
    }
}

PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX sh: <http://www.w3.org/ns/shacl#>

ASK {
    GRAPH <work:schema:overlay> {
        ?property a ?overlayType .
        FILTER(?overlayType IN (owl:AnnotationProperty, owl:ObjectProperty, owl:DatatypeProperty))
    }
    GRAPH <work:schema:derived> {
        ?ps a sh:PropertyShape ;
            sh:path ?property .
        FILTER(isIRI(?property))
    }
}

