sparqlQuery.sparql:
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>
PREFIX sh: <http://www.w3.org/ns/shacl#>
PREFIX dcterms: <http://purl.org/dc/terms/>

SELECT ?metric ?count
WHERE {
    {
        SELECT ("backup_named_triples" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:backup> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
        }
    } UNION {
        SELECT ("derived_named_triples" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:derived> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
        }
    } UNION {
        SELECT ("unexpected_removed_named_raw" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:backup> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:derived> {
                    ?s ?p ?o .
                }
            }
        }
    } UNION {
        SELECT ("unexpected_added_named_raw" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:derived> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:backup> {
                    ?s ?p ?o .
                }
            }
        }
    } UNION {
        SELECT ("unexpected_removed_named_filtered" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:backup> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:derived> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    STRSTARTS(STR(?p), STR(sh:))
                    || (?p = rdf:type && EXISTS { GRAPH <schema:allowlist-shacl-type-object> { ?o a <urn:qudt:allowlist:ShaclSchemaTypeObject> . } })
                    || (?s = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/datatype>)
                    || (?o = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/datatype>)
                )
            }
            FILTER NOT EXISTS {
                GRAPH <schema:allowlist-legacy-removals> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    EXISTS { GRAPH <schema:allowlist-metadata-predicate> { ?p a <urn:qudt:allowlist:MetadataPredicate> . } }
                    && EXISTS { GRAPH <schema:shacl> { ?s ?p ?anyShaclValue . } }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    !EXISTS {
                        GRAPH <schema:shacl> {
                            ?s ?spAny ?soAny .
                            FILTER(!isBlank(?s))
                        }
                    }
                    && !EXISTS {
                        GRAPH <schema:overlay> {
                            ?s ?overlayPAny ?overlayOAny .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p IN (
                        rdf:type,
                        rdfs:subClassOf,
                        owl:equivalentClass,
                        owl:disjointWith,
                        rdfs:subPropertyOf
                    )
                    && (
                        EXISTS { GRAPH <schema:shacl> { ?s ?anyShaclP2 ?anyShaclO2 . } }
                        || EXISTS {
                            GRAPH <schema:shacl> {
                                ?anyPs a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                       <http://www.w3.org/ns/shacl#path> ?s .
                                FILTER(isIRI(?s))
                            }
                        }
                    )
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdf:type
                    && ?o = rdfs:Class
                    && EXISTS { GRAPH <schema:derived> { ?s rdf:type owl:Class . } }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:isDefinedBy
                    && EXISTS { GRAPH <schema:derived> { ?s rdfs:isDefinedBy <http://qudt.org/$$QUDT_VERSION$$/schema/datatype> . } }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:range
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                            {
                                ?ps <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#or> ?anyShaclRangeList .
                                ?anyShaclRangeList <http://www.w3.org/1999/02/22-rdf-syntax-ns#rest>*/<http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?anyShaclRangeChoice .
                                {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                                } UNION {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                                }
                            }
                        }
                    }
                )
            }
        }
    } UNION {
        SELECT ("unexpected_added_named_filtered" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:derived> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:backup> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                GRAPH <schema:allowlist-metadata-added> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                GRAPH <schema:allowlist-added> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    EXISTS { GRAPH <schema:allowlist-metadata-predicate> { ?p a <urn:qudt:allowlist:MetadataPredicate> . } }
                    && EXISTS { GRAPH <schema:shacl> { ?s ?p ?anyShaclValue . } }
                )
            }
            FILTER NOT EXISTS {
                GRAPH <schema:shacl> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p IN (
                        rdf:type,
                        rdfs:subClassOf,
                        owl:equivalentClass,
                        owl:disjointWith,
                        rdfs:subPropertyOf
                    )
                    && (
                        EXISTS { GRAPH <schema:shacl> { ?s ?anyShaclP2 ?anyShaclO2 . } }
                        || EXISTS {
                            GRAPH <schema:shacl> {
                                ?anyPs a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                       <http://www.w3.org/ns/shacl#path> ?s .
                                FILTER(isIRI(?s))
                            }
                        }
                    )
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:isDefinedBy
                    && ?o = <http://qudt.org/$$QUDT_VERSION$$/schema/datatype>
                    && (
                        EXISTS { GRAPH <schema:shacl> { ?s ?anyShaclP ?anyShaclO . } }
                        || EXISTS {
                            GRAPH <schema:shacl> {
                                ?anyPs a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                       <http://www.w3.org/ns/shacl#path> ?s .
                                FILTER(isIRI(?s))
                            }
                        }
                    )
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:range
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                            {
                                ?ps <http://www.w3.org/ns/shacl#class> ?o .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#datatype> ?o .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#or> ?rangeList .
                                ?rangeList <http://www.w3.org/1999/02/22-rdf-syntax-ns#rest>*/<http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?choice .
                                {
                                    ?choice <http://www.w3.org/ns/shacl#class> ?o .
                                } UNION {
                                    ?choice <http://www.w3.org/ns/shacl#datatype> ?o .
                                }
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = <http://www.w3.org/1999/02/22-rdf-syntax-ns#first>
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s <http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?firstSpec .
                            {
                                ?firstSpec <http://www.w3.org/ns/shacl#datatype> ?o .
                            } UNION {
                                ?firstSpec <http://www.w3.org/ns/shacl#class> ?o .
                            }
                        }
                    }
                )
            }
        }
    }
}
ORDER BY ?metric

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX sh: <http://www.w3.org/ns/shacl#>

SELECT ?s ?p ?o
WHERE {
