                }
                FILTER NOT EXISTS {
                    FILTER(
                        EXISTS { GRAPH <schema:allowlist-metadata-predicate> { ?predicate a <urn:qudt:allowlist:MetadataPredicate> . } }
                        && EXISTS { GRAPH <schema:shacl> { ?s ?predicate ?anyShaclValue . } }
                    )
                }
                FILTER NOT EXISTS {
                    FILTER(
                        !EXISTS {
                            GRAPH <schema:shacl> {
                                ?s ?spAny ?soAny .
                                FILTER(!isBlank(?s))
                            }
                        }
                        && !EXISTS {
                            GRAPH <schema:overlay> {
                                ?s ?overlayPAny ?overlayOAny .
                            }
                        }
                    )
                }
                FILTER NOT EXISTS {
                    FILTER(
                        ?predicate IN (
                            rdf:type,
                            rdfs:subClassOf,
                            owl:equivalentClass,
                            owl:disjointWith,
                            rdfs:subPropertyOf
                        )
                        && EXISTS { GRAPH <schema:shacl> { ?s ?anyShaclP2 ?anyShaclO2 . } }
                    )
                }
                FILTER NOT EXISTS {
                    FILTER(
                        ?predicate = rdf:type
                        && ?o = rdfs:Class
                        && EXISTS { GRAPH <schema:derived> { ?s rdf:type owl:Class . } }
                    )
                }
