                                } UNION {
                                    ?firstSpec <http://www.w3.org/ns/shacl#class> ?o .
                                }
                            }
                        }
                    )
                }
                BIND("added" AS ?kind)
            }
        }
        GROUP BY ?kind ?predicate
    }
    BIND(
        IF(?predicate = rdf:type, "Type changes",
            IF(?predicate = rdfs:subClassOf, "Subclass changes",
                IF(?predicate = rdfs:range, "Range changes",
                    IF(?predicate = rdfs:isDefinedBy, "isDefinedBy changes",
                        IF(?predicate = rdfs:label || ?predicate = rdfs:comment || ?predicate = dcterms:description, "Metadata text changes", "Other predicates")
                    )
                )
            )
        ) AS ?bucket
    )
}
GROUP BY ?kind ?bucket
ORDER BY ?kind DESC(?total) ?bucket

