            }
            FILTER NOT EXISTS {
                GRAPH <schema:allowlist-added> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    EXISTS { GRAPH <schema:allowlist-metadata-predicate> { ?p a <urn:qudt:allowlist:MetadataPredicate> . } }
                    && EXISTS { GRAPH <schema:shacl> { ?s ?p ?anyShaclValue . } }
                )
            }
            FILTER NOT EXISTS {
                GRAPH <schema:shacl> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p IN (
                        <http://www.w3.org/1999/02/22-rdf-syntax-ns#type>,
                        <http://www.w3.org/2000/01/rdf-schema#subClassOf>,
                        <http://www.w3.org/2002/07/owl#equivalentClass>,
                        <http://www.w3.org/2002/07/owl#disjointWith>,
                        <http://www.w3.org/2000/01/rdf-schema#subPropertyOf>
                    )
                    && (
                        EXISTS { GRAPH <schema:shacl> { ?s ?anyShaclP2 ?anyShaclO2 . } }
                        || EXISTS {
                            GRAPH <schema:shacl> {
                                ?anyPs a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                       <http://www.w3.org/ns/shacl#path> ?s .
                                FILTER(isIRI(?s))
                            }
                        }
                    )
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:isDefinedBy
                    && ?o = <http://qudt.org/$$QUDT_VERSION$$/schema/datatype>
                    && (
                        EXISTS { GRAPH <schema:shacl> { ?s ?anyShaclP ?anyShaclO . } }
                        || EXISTS {
                            GRAPH <schema:shacl> {
                                ?anyPs a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                       <http://www.w3.org/ns/shacl#path> ?s .
                                FILTER(isIRI(?s))
                            }
                        }
                    )
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:range
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                            {
                                ?ps <http://www.w3.org/ns/shacl#class> ?o .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#datatype> ?o .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#or> ?rangeList .
                                ?rangeList <http://www.w3.org/1999/02/22-rdf-syntax-ns#rest>*/<http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?choice .
                                {
                                    ?choice <http://www.w3.org/ns/shacl#class> ?o .
                                } UNION {
                                    ?choice <http://www.w3.org/ns/shacl#datatype> ?o .
                                }
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = <http://www.w3.org/1999/02/22-rdf-syntax-ns#first>
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s <http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?firstSpec .
                            {
                                ?firstSpec <http://www.w3.org/ns/shacl#datatype> ?o .
                            } UNION {
                                ?firstSpec <http://www.w3.org/ns/shacl#class> ?o .
                            }
                        }
                    }
                )
            }
        }
    }
    FILTER(?count > ${datatype.schema.diff.max.unexpected.added})
}

sparqlQuery.sparql:
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX sh: <http://www.w3.org/ns/shacl#>
PREFIX owl: <http://www.w3.org/2002/07/owl#>

SELECT ?metric ?count
WHERE {
    {
        SELECT ("backup_named_triples" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:backup> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
        }
    } UNION {
        SELECT ("derived_named_triples" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:derived> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
        }
    } UNION {
        SELECT ("expected_removed_shacl_or_ontology_shacl_named" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:backup> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER(
                STRSTARTS(STR(?p), STR(sh:))
                || ( ?p = rdf:type && EXISTS { GRAPH <schema:allowlist-shacl-type-object> { ?o a <urn:qudt:allowlist:ShaclSchemaTypeObject> . } } )
                || (?s = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
                || (?o = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
            )
            FILTER NOT EXISTS {
                GRAPH <schema:derived> {
                    ?s ?p ?o .
                }
            }
        }
    } UNION {
        SELECT ("expected_label_drift_named" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:backup> {
                ?s rdfs:label ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:derived> {
                    ?s rdfs:label ?o .
                }
            }
            FILTER EXISTS {
                GRAPH <schema:shacl> {
                    ?s rdfs:label ?anyShaclLabel .
                }
            }
        }
    } UNION {
        SELECT ("unexpected_removed_named" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:backup> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:derived> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    STRSTARTS(STR(?p), STR(sh:))
                    || ( ?p = rdf:type && EXISTS { GRAPH <schema:allowlist-shacl-type-object> { ?o a <urn:qudt:allowlist:ShaclSchemaTypeObject> . } } )
                    || (?s = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
                    || (?o = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:label
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s rdfs:label ?anyShaclLabel .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = <http://www.w3.org/1999/02/22-rdf-syntax-ns#type>
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s a ?anyShaclType .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:comment
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            {
                                ?s rdfs:comment ?anyShaclComment .
                            } UNION {
                                ?s <http://purl.org/dc/terms/description> ?anyShaclDescription .
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:range
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                            {
                                ?ps <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#or> ?anyShaclRangeList .
                                ?anyShaclRangeList <http://www.w3.org/1999/02/22-rdf-syntax-ns#rest>*/<http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?anyShaclRangeChoice .
                                {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                                } UNION {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                                }
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:domain
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?shaclDomain a <http://www.w3.org/ns/shacl#NodeShape> ;
                                a rdfs:Class ;
                                <http://www.w3.org/ns/shacl#property> ?domainPs .
                            ?domainPs a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    EXISTS {
                        GRAPH <schema:allowlist-metadata-predicate> {
                            ?p a <urn:qudt:allowlist:MetadataPredicate> .
                        }
                    }
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s ?p ?anyShaclMetadataValue .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    !EXISTS {
                        GRAPH <schema:shacl> {
                            ?s ?spAny ?soAny .
                            FILTER(!isBlank(?s))
                        }
                    }
                    && !EXISTS {
                        GRAPH <schema:overlay> {
                            ?s ?overlayPAny ?overlayOAny .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:range
                    && EXISTS {
                        GRAPH <schema:allowlist-legacy-range-property> {
                            ?s a <urn:qudt:allowlist:LegacyRangeProperty> .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:range
                    && EXISTS {
                        GRAPH <schema:allowlist-stub-range-property> {
                            ?s a <urn:qudt:allowlist:StubRangeProperty> .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                GRAPH <schema:allowlist-metadata-added> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                GRAPH <schema:allowlist-legacy-removals> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    EXISTS {
                        GRAPH <schema:datatypes-shacl> {
                            ?s ?dtAnyP ?dtAnyO .
                            FILTER(!isBlank(?s))
                        }
                    }
                )
            }
        }
    } UNION {
        SELECT ("unexpected_added_named" AS ?metric) (COUNT(*) AS ?count)
        WHERE {
            GRAPH <schema:derived> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:backup> {
                    ?s ?p ?o .
                }
            }
            FILTER(
                ?s != <http://qudt.org/$$QUDT_VERSION$$/schema/qudt>
                && ?o != <http://qudt.org/$$QUDT_VERSION$$/schema/qudt>
            )
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:label
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s rdfs:label ?o .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = <http://www.w3.org/1999/02/22-rdf-syntax-ns#type>
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s a ?anyShaclType .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:comment
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            {
                                ?s rdfs:comment ?anyShaclComment .
                            } UNION {
                                ?s <http://purl.org/dc/terms/description> ?anyShaclDescription .
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:range
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                            {
                                ?ps <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#or> ?anyShaclRangeList .
                                ?anyShaclRangeList <http://www.w3.org/1999/02/22-rdf-syntax-ns#rest>*/<http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?anyShaclRangeChoice .
                                {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                                } UNION {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                                }
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:domain
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?shaclDomain a <http://www.w3.org/ns/shacl#NodeShape> ;
                                a rdfs:Class ;
                                <http://www.w3.org/ns/shacl#property> ?domainPs .
                            ?domainPs a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    EXISTS {
                        GRAPH <schema:allowlist-metadata-predicate> {
                            ?p a <urn:qudt:allowlist:MetadataPredicate> .
                        }
                    }
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s ?p ?anyShaclMetadataValue .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                GRAPH <schema:shacl> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = rdfs:range
                    && EXISTS {
                        GRAPH <schema:allowlist-stub-range-property> {
                            ?s a <urn:qudt:allowlist:StubRangeProperty> .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                GRAPH <schema:allowlist-metadata-added> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?p = <http://www.w3.org/1999/02/22-rdf-syntax-ns#type>
                    && EXISTS {
                        GRAPH <schema:allowlist-property-type-object> {
                            ?o a <urn:qudt:allowlist:ShaclPathPropertyTypeObject> .
                        }
                    }
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                        }
                    }
                )
            }
        }
    }
}
ORDER BY ?metric

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX sh: <http://www.w3.org/ns/shacl#>

SELECT ?s ?p ?o
WHERE {
    GRAPH <schema:backup> {
        ?s ?p ?o .
        FILTER(!isBlank(?s) && !isBlank(?o))
    }
    FILTER(
        STRSTARTS(STR(?p), STR(sh:))
        || ( ?p = rdf:type && EXISTS { GRAPH <schema:allowlist-shacl-type-object> { ?o a <urn:qudt:allowlist:ShaclSchemaTypeObject> . } } )
        || (?s = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
        || (?o = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
    )
    FILTER NOT EXISTS {
        GRAPH <schema:derived> {
            ?s ?p ?o .
        }
    }
}
ORDER BY ?s ?p ?o

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?s ?backupLabel ?shaclLabel
WHERE {
    GRAPH <schema:backup> {
        ?s rdfs:label ?backupLabel .
        FILTER(!isBlank(?s) && !isBlank(?backupLabel))
    }
    GRAPH <schema:shacl> {
        ?s rdfs:label ?shaclLabel .
    }
    FILTER(?backupLabel != ?shaclLabel)
}
ORDER BY ?s ?backupLabel ?shaclLabel

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>

SELECT ?s ?backupComment ?shaclComment
WHERE {
    GRAPH <schema:backup> {
        ?s rdfs:comment ?backupComment .
        FILTER(!isBlank(?s) && !isBlank(?backupComment))
    }
    GRAPH <schema:shacl> {
        ?s rdfs:comment ?shaclComment .
    }
    FILTER(?backupComment != ?shaclComment)
}
ORDER BY ?s ?backupComment ?shaclComment

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX sh: <http://www.w3.org/ns/shacl#>
PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?property ?backupRange ?shaclRange
WHERE {
    GRAPH <schema:backup> {
        ?property rdfs:range ?backupRange .
        FILTER(!isBlank(?property) && !isBlank(?backupRange))
    }
    GRAPH <schema:shacl> {
        ?ps a sh:PropertyShape ;
            sh:path ?property .
        FILTER(isIRI(?property))
        {
            ?ps sh:class ?shaclRange .
        } UNION {
            ?ps sh:datatype ?shaclRange .
        } UNION {
            ?ps sh:or ?rangeList .
            ?rangeList rdf:rest*/rdf:first ?choice .
            {
                ?choice sh:class ?shaclRange .
            } UNION {
                ?choice sh:datatype ?shaclRange .
            }
        }
    }
    FILTER(?backupRange != ?shaclRange)
}
ORDER BY ?property ?backupRange ?shaclRange

PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX sh: <http://www.w3.org/ns/shacl#>

SELECT ?property ?backupDomain ?shaclDomain
WHERE {
    GRAPH <schema:backup> {
        ?property rdfs:domain ?backupDomain .
        FILTER(!isBlank(?property) && !isBlank(?backupDomain))
    }
    GRAPH <schema:shacl> {
        ?shaclDomain a sh:NodeShape ;
                     a rdfs:Class ;
                     sh:property ?ps .
        ?ps a sh:PropertyShape ;
            sh:path ?property .
        FILTER(isIRI(?property))
    }
    FILTER(?backupDomain != ?shaclDomain)
}
ORDER BY ?property ?backupDomain ?shaclDomain

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>

SELECT ?s ?backupType ?shaclType
WHERE {
    GRAPH <schema:backup> {
        ?s rdf:type ?backupType .
        FILTER(!isBlank(?s) && !isBlank(?backupType))
    }
    GRAPH <schema:shacl> {
        ?s rdf:type ?shaclType .
    }
    FILTER(?backupType != ?shaclType)
}
ORDER BY ?s ?backupType ?shaclType

SELECT ?s ?p ?backupValue ?shaclValue
WHERE {
    VALUES ?p {
        <http://purl.org/dc/terms/description>
        <http://qudt.org/schema/qudt/informativeReference>
        <http://qudt.org/schema/qudt/plainTextDescription>
        <http://qudt.org/schema/qudt/dbpediaMatch>
    }
    GRAPH <schema:backup> {
        ?s ?p ?backupValue .
        FILTER(!isBlank(?s) && !isBlank(?backupValue))
    }
    GRAPH <schema:shacl> {
        ?s ?p ?shaclValue .
    }
    FILTER(?backupValue != ?shaclValue)
}
ORDER BY ?s ?p ?backupValue ?shaclValue

SELECT ?s ?p ?o
WHERE {
    GRAPH <schema:backup> {
        ?s ?p ?o .
        FILTER(!isBlank(?s) && !isBlank(?o))
    }
    FILTER NOT EXISTS {
        GRAPH <schema:derived> {
            ?s ?p ?o .
        }
    }
    FILTER(
        !EXISTS {
            GRAPH <schema:shacl> {
                ?s ?spAny ?soAny .
                FILTER(!isBlank(?s))
            }
        }
        && !EXISTS {
            GRAPH <schema:overlay> {
                ?s ?overlayPAny ?overlayOAny .
            }
        }
    )
}
ORDER BY ?s ?p ?o

SELECT ?s ?p ?o
WHERE {
    GRAPH <schema:backup> {
        ?s ?p ?o .
        FILTER(!isBlank(?s) && !isBlank(?o))
    }
    FILTER NOT EXISTS {
        GRAPH <schema:derived> {
            ?s ?p ?o .
        }
    }
    FILTER EXISTS {
        GRAPH <schema:datatypes-shacl> {
            ?s ?dtAnyP ?dtAnyO .
            FILTER(!isBlank(?s))
        }
    }
}
ORDER BY ?s ?p ?o

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX sh: <http://www.w3.org/ns/shacl#>

SELECT ?s ?p ?o
WHERE {
    GRAPH <schema:backup> {
        ?s ?p ?o .
        FILTER(!isBlank(?s) && !isBlank(?o))
    }
    FILTER NOT EXISTS {
        GRAPH <schema:derived> {
            ?s ?p ?o .
        }
    }
    FILTER NOT EXISTS {
        FILTER(
            STRSTARTS(STR(?p), STR(sh:))
            || ( ?p = rdf:type && EXISTS { GRAPH <schema:allowlist-shacl-type-object> { ?o a <urn:qudt:allowlist:ShaclSchemaTypeObject> . } } )
            || (?s = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
            || (?o = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
        )
    }
    FILTER NOT EXISTS {
        FILTER(
            ?p = rdfs:label
            && EXISTS {
                GRAPH <schema:shacl> {
                    ?s rdfs:label ?anyShaclLabel .
                }
            }
        )
    }
    FILTER NOT EXISTS {
        FILTER(
            ?p = <http://www.w3.org/1999/02/22-rdf-syntax-ns#type>
            && EXISTS {
                GRAPH <schema:shacl> {
                    ?s a ?anyShaclType .
                }
            }
        )
    }
    FILTER NOT EXISTS {
        FILTER(
            ?p = rdfs:comment
            && EXISTS {
                GRAPH <schema:shacl> {
                    {
                        ?s rdfs:comment ?anyShaclComment .
                    } UNION {
                        ?s <http://purl.org/dc/terms/description> ?anyShaclDescription .
                    }
                }
            }
        )
    }
    FILTER NOT EXISTS {
        FILTER(
            ?p = rdfs:range
            && EXISTS {
                GRAPH <schema:shacl> {
                    ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                        <http://www.w3.org/ns/shacl#path> ?s .
                    FILTER(isIRI(?s))
                    {
                        ?ps <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                    } UNION {
                        ?ps <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                    } UNION {
                        ?ps <http://www.w3.org/ns/shacl#or> ?anyShaclRangeList .
                        ?anyShaclRangeList <http://www.w3.org/1999/02/22-rdf-syntax-ns#rest>*/<http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?anyShaclRangeChoice .
                        {
                            ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                        } UNION {
                            ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                        }
                    }
                }
            }
        )
    }
    FILTER NOT EXISTS {
        FILTER(
            ?p = rdfs:domain
            && EXISTS {
                GRAPH <schema:shacl> {
                    ?shaclDomain a <http://www.w3.org/ns/shacl#NodeShape> ;
                                 a rdfs:Class ;
                                 <http://www.w3.org/ns/shacl#property> ?domainPs .
