                                ?anyShaclRangeList <http://www.w3.org/1999/02/22-rdf-syntax-ns#rest>*/<http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?anyShaclRangeChoice .
                                {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                                } UNION {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                                }
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:domain
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?shaclDomain a <http://www.w3.org/ns/shacl#NodeShape> ;
                                         a rdfs:Class ;
                                         <http://www.w3.org/ns/shacl#property> ?domainPs .
                            ?domainPs a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                      <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    EXISTS {
                        GRAPH <schema:allowlist-metadata-predicate> {
                            ?predicate a <urn:qudt:allowlist:MetadataPredicate> .
                        }
                    }
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s ?predicate ?anyShaclMetadataValue .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                GRAPH <schema:shacl> {
                    ?s ?predicate ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = <http://www.w3.org/1999/02/22-rdf-syntax-ns#type>
                    && EXISTS {
                        GRAPH <schema:allowlist-property-type-object> {
                            ?o a <urn:qudt:allowlist:ShaclPathPropertyTypeObject> .
                        }
                    }
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                        }
                    }
                )
            }
        }
        GROUP BY ?direction ?predicate
    }
    BIND(EXISTS {
        GRAPH <schema:shacl> {
            ?ps a sh:PropertyShape ;
                sh:path ?predicate .
        }
    } AS ?isShaclConstrained)
    BIND(EXISTS {
        GRAPH <schema:overlay> {
            ?overlayS ?predicate ?overlayO .
        }
    } AS ?overlayUsesAsPredicate)
    BIND(EXISTS {
        GRAPH <schema:overlay> {
            ?predicate ?overlayP ?overlayV .
        }
    } AS ?overlayDefinesAsSubject)
}
ORDER BY ?direction DESC(?count) ?predicate

PREFIX rdf: <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX sh: <http://www.w3.org/ns/shacl#>

SELECT ?bucket ?direction ?predicate ?count ?isShaclConstrained ?overlayUsesAsPredicate ?overlayDefinesAsSubject
WHERE {
    {
        SELECT ?direction ?predicate (COUNT(*) AS ?count)
        WHERE {
            BIND("unexpected_removed_named" AS ?direction)
            GRAPH <schema:backup> {
                ?s ?predicate ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:derived> {
                    ?s ?predicate ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    STRSTARTS(STR(?predicate), STR(sh:))
                    || ( ?predicate = rdf:type && EXISTS { GRAPH <schema:allowlist-shacl-type-object> { ?o a <urn:qudt:allowlist:ShaclSchemaTypeObject> . } } )
                    || (?s = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
                    || (?o = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:label
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s rdfs:label ?anyShaclLabel .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = <http://www.w3.org/1999/02/22-rdf-syntax-ns#type>
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s a ?anyShaclType .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:comment
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            {
                                ?s rdfs:comment ?anyShaclComment .
                            } UNION {
                                ?s <http://purl.org/dc/terms/description> ?anyShaclDescription .
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:range
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                            {
                                ?ps <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#or> ?anyShaclRangeList .
                                ?anyShaclRangeList <http://www.w3.org/1999/02/22-rdf-syntax-ns#rest>*/<http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?anyShaclRangeChoice .
                                {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                                } UNION {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                                }
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:domain
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?shaclDomain a <http://www.w3.org/ns/shacl#NodeShape> ;
                                         a rdfs:Class ;
                                         <http://www.w3.org/ns/shacl#property> ?domainPs .
                            ?domainPs a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                      <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    EXISTS {
                        GRAPH <schema:allowlist-metadata-predicate> {
                            ?predicate a <urn:qudt:allowlist:MetadataPredicate> .
                        }
                    }
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s ?predicate ?anyShaclMetadataValue .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    !EXISTS {
                        GRAPH <schema:shacl> {
                            ?s ?spAny ?soAny .
                            FILTER(!isBlank(?s))
                        }
                    }
                    && !EXISTS {
                        GRAPH <schema:overlay> {
                            ?s ?overlayPAny ?overlayOAny .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:range
                    && EXISTS {
                        GRAPH <schema:allowlist-legacy-range-property> {
                            ?s a <urn:qudt:allowlist:LegacyRangeProperty> .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:range
                    && EXISTS {
                        GRAPH <schema:allowlist-stub-range-property> {
                            ?s a <urn:qudt:allowlist:StubRangeProperty> .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                GRAPH <schema:allowlist-metadata-added> {
                    ?s ?predicate ?o .
                }
            }
            FILTER NOT EXISTS {
                GRAPH <schema:allowlist-legacy-removals> {
                    ?s ?predicate ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    EXISTS {
                        GRAPH <schema:datatypes-shacl> {
                            ?s ?dtAnyP ?dtAnyO .
                            FILTER(!isBlank(?s))
                        }
                    }
                )
            }
        }
        GROUP BY ?direction ?predicate
    } UNION {
        SELECT ?direction ?predicate (COUNT(*) AS ?count)
        WHERE {
            BIND("unexpected_added_named" AS ?direction)
            GRAPH <schema:derived> {
                ?s ?predicate ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:backup> {
                    ?s ?predicate ?o .
                }
            }
            FILTER(
                ?s != <http://qudt.org/$$QUDT_VERSION$$/schema/qudt>
                && ?o != <http://qudt.org/$$QUDT_VERSION$$/schema/qudt>
            )
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:label
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s rdfs:label ?o .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = <http://www.w3.org/1999/02/22-rdf-syntax-ns#type>
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s a ?anyShaclType .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:comment
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            {
                                ?s rdfs:comment ?anyShaclComment .
                            } UNION {
                                ?s <http://purl.org/dc/terms/description> ?anyShaclDescription .
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:range
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                            {
                                ?ps <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                            } UNION {
                                ?ps <http://www.w3.org/ns/shacl#or> ?anyShaclRangeList .
                                ?anyShaclRangeList <http://www.w3.org/1999/02/22-rdf-syntax-ns#rest>*/<http://www.w3.org/1999/02/22-rdf-syntax-ns#first> ?anyShaclRangeChoice .
                                {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#class> ?anyShaclRange .
                                } UNION {
                                    ?anyShaclRangeChoice <http://www.w3.org/ns/shacl#datatype> ?anyShaclRange .
                                }
                            }
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = rdfs:domain
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?shaclDomain a <http://www.w3.org/ns/shacl#NodeShape> ;
                                         a rdfs:Class ;
                                         <http://www.w3.org/ns/shacl#property> ?domainPs .
                            ?domainPs a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                      <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                FILTER(
                    EXISTS {
                        GRAPH <schema:allowlist-metadata-predicate> {
                            ?predicate a <urn:qudt:allowlist:MetadataPredicate> .
                        }
                    }
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?s ?predicate ?anyShaclMetadataValue .
                        }
                    }
                )
            }
            FILTER NOT EXISTS {
                GRAPH <schema:shacl> {
                    ?s ?predicate ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    ?predicate = <http://www.w3.org/1999/02/22-rdf-syntax-ns#type>
                    && EXISTS {
                        GRAPH <schema:allowlist-property-type-object> {
                            ?o a <urn:qudt:allowlist:ShaclPathPropertyTypeObject> .
                        }
                    }
                    && EXISTS {
                        GRAPH <schema:shacl> {
                            ?ps a <http://www.w3.org/ns/shacl#PropertyShape> ;
                                <http://www.w3.org/ns/shacl#path> ?s .
                            FILTER(isIRI(?s))
                        }
                    }
                )
            }
        }
        GROUP BY ?direction ?predicate
    }
    BIND(EXISTS {
        GRAPH <schema:shacl> {
            ?ps a sh:PropertyShape ;
                sh:path ?predicate .
        }
    } AS ?isShaclConstrained)
    BIND(EXISTS {
        GRAPH <schema:overlay> {
            ?overlayS ?predicate ?overlayO .
        }
    } AS ?overlayUsesAsPredicate)
    BIND(EXISTS {
        GRAPH <schema:overlay> {
            ?predicate ?overlayP ?overlayV .
        }
    } AS ?overlayDefinesAsSubject)
    BIND(
        IF(
            ?isShaclConstrained,
            "SHACL-derived keep",
            IF(
                ?overlayUsesAsPredicate || ?overlayDefinesAsSubject,
                "Overlay candidate",
                "Metadata drift"
            )
        ) AS ?bucket
    )
}
ORDER BY ?bucket ?direction DESC(?count) ?predicate

when.sparqlAsk:
ASK {
    {
        SELECT (COUNT(*) AS ?unexpectedRemovedCount)
        WHERE {
            GRAPH <schema:backup> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:derived> {
                    ?s ?p ?o .
                }
            }
            FILTER NOT EXISTS {
                FILTER(
                    STRSTARTS(STR(?p), "http://www.w3.org/ns/shacl#")
                    || ( ?p = <http://www.w3.org/1999/02/22-rdf-syntax-ns#type> && EXISTS { GRAPH <schema:allowlist-shacl-type-object> { ?o a <urn:qudt:allowlist:ShaclSchemaTypeObject> . } } )
                    || (?s = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
                    || (?o = <http://qudt.org/$$QUDT_VERSION$$/schema/shacl/qudt>)
                )
            }
        }
    }
    {
        SELECT (COUNT(*) AS ?unexpectedAddedCount)
        WHERE {
            GRAPH <schema:derived> {
                ?s ?p ?o .
                FILTER(!isBlank(?s) && !isBlank(?o))
            }
            FILTER NOT EXISTS {
                GRAPH <schema:backup> {
                    ?s ?p ?o .
                }
            }
            FILTER(
                ?s != <http://qudt.org/$$QUDT_VERSION$$/schema/qudt>
                && ?o != <http://qudt.org/$$QUDT_VERSION$$/schema/qudt>
            )
        }
    }
    FILTER(
        ?unexpectedRemovedCount > ${schema.diff.max.unexpected.removed}
        || ?unexpectedAddedCount > ${schema.diff.max.unexpected.added}
    )
}

stop.message:
Schema diff inspection exceeded thresholds.
See target/inspection/schema-diff/{summary,unexpected-added,unexpected-removed}.txt
Thresholds:
- schema.diff.max.unexpected.removed=${schema.diff.max.unexpected.removed}
- schema.diff.max.unexpected.added=${schema.diff.max.unexpected.added}
